import{_ as e,o as r,c as s,a2 as t}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"面试实录","description":"","frontmatter":{"title":"面试实录","author":"","collection":"职场成长","series_order":7,"total_chars":1332},"headers":[],"relativePath":"career/interview-record.md","filePath":"career/interview-record.md"}'),o={name:"career/interview-record.md"};function n(h,a,i,l,d,c){return r(),s("div",null,[...a[0]||(a[0]=[t('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p><a href="#s-453" class="page-toc-link">面试实录：大厂裸辞系列</a>     <a href="#s-454" class="page-toc-link">【面试实录】大厂裸辞一年还能找到工作吗？｜面试准备流程</a>     <a href="#s-458" class="page-toc-link">【面试实录】大厂裸辞一年还能找到工作吗？｜面试题拆解</a>     <a href="#s-461" class="page-toc-link">【面试实录】大厂裸辞一年还能找到工作吗？｜面试实战：自我介绍与选公司逻辑</a>     <a href="#s-465" class="page-toc-link">【面试实录】大厂裸辞一年还能找到工作吗？｜如何展示独特价值</a>     <a href="#s-469" class="page-toc-link">【面试实录】大厂裸辞一年还能找到工作吗？｜反问环节与面试官视角</a>     <a href="#s-473" class="page-toc-link">【面试实录】大厂裸辞一年还能找到工作吗？｜面试反馈与职场甜蜜区</a></div><h2 id="s-453" tabindex="-1">面试实录：大厂裸辞系列 <a class="header-anchor" href="#s-453" aria-label="Permalink to &quot;面试实录：大厂裸辞系列 {#s-453}&quot;">​</a></h2><p>共6个视频</p><h3 id="s-454" tabindex="-1">【面试实录】大厂裸辞一年还能找到工作吗？｜面试准备流程 <a class="header-anchor" href="#s-454" aria-label="Permalink to &quot;【面试实录】大厂裸辞一年还能找到工作吗？｜面试准备流程 {#s-454}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-455" tabindex="-1">1. 公司分ABC三梯队，梯队越高准备越重，认真准备不超6家 <a class="header-anchor" href="#s-455" aria-label="Permalink to &quot;1. 公司分ABC三梯队，梯队越高准备越重，认真准备不超6家 {#s-455}&quot;">​</a></h4><h4 id="s-456" tabindex="-1">2. 根据JD改写简历，甚至简历主题色与公司LOGO统一 <a class="header-anchor" href="#s-456" aria-label="Permalink to &quot;2. 根据JD改写简历，甚至简历主题色与公司LOGO统一 {#s-456}&quot;">​</a></h4><h4 id="s-457" tabindex="-1">3. 刚毕业或在校生可多准备公司提高上岸概率 <a class="header-anchor" href="#s-457" aria-label="Permalink to &quot;3. 刚毕业或在校生可多准备公司提高上岸概率 {#s-457}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「认真地准备公司不会超过六家」</em></p><p><strong>行动指南</strong></p><p>按梯队分级准备目标公司，每家公司定制化简历</p><h3 id="s-458" tabindex="-1">【面试实录】大厂裸辞一年还能找到工作吗？｜面试题拆解 <a class="header-anchor" href="#s-458" aria-label="Permalink to &quot;【面试实录】大厂裸辞一年还能找到工作吗？｜面试题拆解 {#s-458}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-459" tabindex="-1">1. 80%面试题可提前准备——面试通过与否在面试前已定 <a class="header-anchor" href="#s-459" aria-label="Permalink to &quot;1. 80%面试题可提前准备——面试通过与否在面试前已定 {#s-459}&quot;">​</a></h4><p>**2. **通用题（HR问稳定性、素质、行业经验）vs特殊业务题（Leader问业务深度）</p><p>**3. **通用题别用套路（&quot;我的缺点是太完美主义&quot;HR一听就知道抄的），要真诚融入个人思考</p><h4 id="s-460" tabindex="-1">4. 特殊业务题根据JD倒推对方会问什么，准备回答框架 <a class="header-anchor" href="#s-460" aria-label="Permalink to &quot;4. 特殊业务题根据JD倒推对方会问什么，准备回答框架 {#s-460}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「面试会不会通过，其实在面试前就已经定胜负了」</em></p><p><strong>行动指南</strong></p><p>提前按JD拆解准备面试题，通用题真诚回答，业务题做框架准备</p><h3 id="s-461" tabindex="-1">【面试实录】大厂裸辞一年还能找到工作吗？｜面试实战：自我介绍与选公司逻辑 <a class="header-anchor" href="#s-461" aria-label="Permalink to &quot;【面试实录】大厂裸辞一年还能找到工作吗？｜面试实战：自我介绍与选公司逻辑 {#s-461}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-462" tabindex="-1">1. 自我介绍聚焦核心经历和价值贡献，不是流水账 <a class="header-anchor" href="#s-462" aria-label="Permalink to &quot;1. 自我介绍聚焦核心经历和价值贡献，不是流水账 {#s-462}&quot;">​</a></h4><h4 id="s-463" tabindex="-1">2. 选公司三层逻辑：大赛道→公司→个人动机匹配 <a class="header-anchor" href="#s-463" aria-label="Permalink to &quot;2. 选公司三层逻辑：大赛道→公司→个人动机匹配 {#s-463}&quot;">​</a></h4><h4 id="s-464" tabindex="-1">3. 夸公司要具体到特点（如&quot;混血气质&quot;而非泛泛而谈），展示你做过功课 <a class="header-anchor" href="#s-464" aria-label="Permalink to &quot;3. 夸公司要具体到特点（如&quot;混血气质&quot;而非泛泛而谈），展示你做过功课 {#s-464}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「我自己也是致力于想做一个有一定混血气质的职场人」</em></p><p><strong>行动指南</strong></p><p>自我介绍提炼三段核心经历，面试前深入研究公司独特文化</p><h3 id="s-465" tabindex="-1">【面试实录】大厂裸辞一年还能找到工作吗？｜如何展示独特价值 <a class="header-anchor" href="#s-465" aria-label="Permalink to &quot;【面试实录】大厂裸辞一年还能找到工作吗？｜如何展示独特价值 {#s-465}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-466" tabindex="-1">1. 解释岗位选择要真诚：先是命运选择，后是真心热爱 <a class="header-anchor" href="#s-466" aria-label="Permalink to &quot;1. 解释岗位选择要真诚：先是命运选择，后是真心热爱 {#s-466}&quot;">​</a></h4><h4 id="s-467" tabindex="-1">2. 坦诚表达成长困惑比装懂更有说服力 <a class="header-anchor" href="#s-467" aria-label="Permalink to &quot;2. 坦诚表达成长困惑比装懂更有说服力 {#s-467}&quot;">​</a></h4><p>**3. **展示独特价值三维：业务价值（行业前20%）、用户价值（连接年轻用户）、社会价值</p><h4 id="s-468" tabindex="-1">4. 运营不是具体岗位而是通用能力，可放大任何业务 <a class="header-anchor" href="#s-468" aria-label="Permalink to &quot;4. 运营不是具体岗位而是通用能力，可放大任何业务 {#s-468}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「运营不是一个具体的岗位，它像沟通、统筹一样是一种通用的能力」</em></p><p><strong>行动指南</strong></p><p>面试时从业务、用户、社会三个维度展示独特价值，坦诚面对成长困惑</p><h3 id="s-469" tabindex="-1">【面试实录】大厂裸辞一年还能找到工作吗？｜反问环节与面试官视角 <a class="header-anchor" href="#s-469" aria-label="Permalink to &quot;【面试实录】大厂裸辞一年还能找到工作吗？｜反问环节与面试官视角 {#s-469}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-470" tabindex="-1">1. 反问环节问岗位期待和项目定位，展示你认真对待这份工作 <a class="header-anchor" href="#s-470" aria-label="Permalink to &quot;1. 反问环节问岗位期待和项目定位，展示你认真对待这份工作 {#s-470}&quot;">​</a></h4><h4 id="s-471" tabindex="-1">2. 面试官看重：真实、好学、有追求 <a class="header-anchor" href="#s-471" aria-label="Permalink to &quot;2. 面试官看重：真实、好学、有追求 {#s-471}&quot;">​</a></h4><h4 id="s-472" tabindex="-1">3. 入职后喜爱度随自主权提升而增长——用自己的想法踩上去才有真正成就感 <a class="header-anchor" href="#s-472" aria-label="Permalink to &quot;3. 入职后喜爱度随自主权提升而增长——用自己的想法踩上去才有真正成就感 {#s-472}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「每一步台阶是我真真用自己的想法去踩上来的时候，这种成就感和价值感是不一样的」</em></p><p><strong>行动指南</strong></p><p>面试反问时关注岗位自主权和成长空间，选择给自己自由度的公司</p><h3 id="s-473" tabindex="-1">【面试实录】大厂裸辞一年还能找到工作吗？｜面试反馈与职场甜蜜区 <a class="header-anchor" href="#s-473" aria-label="Permalink to &quot;【面试实录】大厂裸辞一年还能找到工作吗？｜面试反馈与职场甜蜜区 {#s-473}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-474" tabindex="-1">1. 面试加分点：所有优点都与岗位挂钩，而非泛泛自夸 <a class="header-anchor" href="#s-474" aria-label="Permalink to &quot;1. 面试加分点：所有优点都与岗位挂钩，而非泛泛自夸 {#s-474}&quot;">​</a></h4><h4 id="s-475" tabindex="-1">2. 面试减分点：单向输出太强，没考虑面试官接受度——视频面试要有暂缓等反馈 <a class="header-anchor" href="#s-475" aria-label="Permalink to &quot;2. 面试减分点：单向输出太强，没考虑面试官接受度——视频面试要有暂缓等反馈 {#s-475}&quot;">​</a></h4><h4 id="s-476" tabindex="-1">3. 当大家都在学套路时，坦诚反而是更好的策略——一诚可以抵万术 <a class="header-anchor" href="#s-476" aria-label="Permalink to &quot;3. 当大家都在学套路时，坦诚反而是更好的策略——一诚可以抵万术 {#s-476}&quot;">​</a></h4><h4 id="s-477" tabindex="-1">4. 职场甜蜜区=热爱+擅长+市场有价值，三者交集是最佳定位 <a class="header-anchor" href="#s-477" aria-label="Permalink to &quot;4. 职场甜蜜区=热爱+擅长+市场有价值，三者交集是最佳定位 {#s-477}&quot;">​</a></h4><h4 id="s-478" tabindex="-1">5. 求职最大困难：双方互相不知道怎么匹配 <a class="header-anchor" href="#s-478" aria-label="Permalink to &quot;5. 求职最大困难：双方互相不知道怎么匹配 {#s-478}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「当大家都在学习套路的时候，你非常的坦诚，反而也许是一个更好的套路」</em></p><p><strong>行动指南</strong></p><p>视频面试注意停顿等面试官反馈，回答真实坦诚，找到自己的职场甜蜜区</p>',61)])])}const q=e(o,[["render",n]]);export{u as __pageData,q as default};
